const FONT_BASE64 = "";

const { jsPDF } = window.jspdf;
const A4_W = 2480;
const A4_H = 3508;
const MARGIN_X = 200;

let state = {
    text: document.getElementById('textInput').value,
    fontSize: 90,
    lineSpacing: 120,
    opacity: 0.2,
    fontFamily: 'ElementarzCustom'
};

const canvas = document.getElementById('previewCanvas');
const ctx = canvas.getContext('2d');

async function injectFont() {
    if (FONT_BASE64.length < 100) {
        document.getElementById('fontStatus').innerHTML = "<b style='color:red'>Błąd: Wklej kod Base64 wewnątrz pliku HTML!</b>";
        return;
    }

    const fontData = `url(data:font/ttf;base64,${FONT_BASE64})`;
    const myFont = new FontFace(state.fontFamily, fontData);

    try {
        const loadedFace = await myFont.load();
        document.fonts.add(loadedFace);
        document.getElementById('textInput').style.fontFamily = state.fontFamily;
        document.getElementById('fontStatus').innerText = "Czcionka wstrzyknięta pomyślnie ✅";
        updateApp();
    } catch (err) {
        document.getElementById('fontStatus').innerText = "Błąd wstrzykiwania Base64 ❌";
    }
}

function renderPage(rows) {
    canvas.width = A4_W;
    canvas.height = A4_H;
    ctx.fillStyle = "white";
    ctx.fillRect(0, 0, A4_W, A4_H);

    rows.forEach((rowText, idx) => {
        const y = (idx + 1) * state.lineSpacing;
        if (y > A4_H - 100) return;

        // Baseline
        ctx.beginPath();
        ctx.strokeStyle = "#cbd5e1";
        ctx.lineWidth = 2;
        ctx.moveTo(MARGIN_X, y);
        ctx.lineTo(A4_W - MARGIN_X, y);
        ctx.stroke();

        // Trace Text
        ctx.globalAlpha = state.opacity;
        ctx.font = `${state.fontSize}px ${state.fontFamily}`;
        ctx.textBaseline = "alphabetic";
        ctx.fillStyle = "black";
        ctx.fillText(rowText, MARGIN_X, y);
        ctx.globalAlpha = 1.0;
    });
}

function updateApp() {
    const lines = state.text.split('\n');
    const linesPerPage = Math.floor((A4_H - 100) / state.lineSpacing);
    renderPage(lines.slice(0, linesPerPage));
}

async function downloadPDF() {
    const btn = document.getElementById('downloadPdf');
    btn.innerText = "Trwa eksport...";
    const lines = state.text.split('\n');
    const linesPerPage = Math.floor((A4_H - 100) / state.lineSpacing);
    const totalPages = Math.ceil(lines.length / linesPerPage);

    const pdf = new jsPDF({ orientation: "p", unit: "px", format: [A4_W, A4_H] });

    for (let i = 0; i < totalPages; i++) {
        if (i > 0) pdf.addPage([A4_W, A4_H], "p");
        renderPage(lines.slice(i * linesPerPage, (i + 1) * linesPerPage));
        const imgData = canvas.toDataURL("image/jpeg", 0.95);
        pdf.addImage(imgData, 'JPEG', 0, 0, A4_W, A4_H);
    }

    pdf.save("arkusz-cwiczen.pdf");
    btn.innerText = "Generuj PDF";
    updateApp();
}

const inputs = [{ id: 'textInput', key: 'text' }, { id: 'fontSize', key: 'fontSize', isInt: true }, { id: 'lineSpacing', key: 'lineSpacing', isInt: true }, { id: 'opacity', key: 'opacity', isFloat: true }];

inputs.forEach(item => {
    const el = document.getElementById(item.id);
    if (el) el.value = state[item.key];
    const valLabel = document.getElementById(item.id + 'Val');
    if (valLabel) valLabel.innerText = state[item.key];
});

inputs.forEach(item => {
    document.getElementById(item.id).addEventListener('input', (e) => {
        let val = e.target.value;
        if (item.isInt) val = parseInt(val, 10);
        if (item.isFloat) val = parseFloat(val);
        state[item.key] = val;
        if (document.getElementById(item.id + 'Val')) document.getElementById(item.id + 'Val').innerText = val;
        updateApp();
    });
});

document.getElementById('downloadPdf').addEventListener('click', downloadPDF);

injectFont();
